INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(15,'atividades da charlen','proposta da charlen','relacionamentos da charlen','segmentos da charlen','recursos da charlen','canais da charlen','custos da charlen','assinaturas mensais','parceiros da charlen',1,'charlen');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(16,'Desenvolvimento contínuo da infraestrutura cloud, manutenção preventiva de servidores de alta disponibilidade, criação de algoritmos de inteligência artificial para personalização de conteúdo e suporte técnico especializado em tempo real para usuários premium.','Oferecer uma experiência de aprendizagem imersiva e totalmente personalizada, garantindo que estudantes da região da Serra Gaúcha tenham acesso a tecnologias de ponta e metodologias ativas que facilitam a inserção imediata no mercado de trabalho tecnológico.','Atendimento humanizado através de múltiplos canais, fóruns comunitários moderados por especialistas, programas de fidelidade com gamificação e consultoria estratégica para planos corporativos de larga escala.','Estudantes de cursos técnicos e superiores, profissionais em transição de carreira, empresas de tecnologia que buscam treinar suas equipes internamente e instituições de ensino públicas e privadas localizadas no Rio Grande do Sul.','Equipe de desenvolvedores seniores, servidores escaláveis na AWS, licenças de softwares de edição profissional, laboratórios físicos de teste e banco de dados proprietário com milhares de questões resolvidas.','Portal web responsivo, aplicativo móvel nativo para Android e iOS, redes sociais estratégicas (LinkedIn e Instagram) e parcerias diretas com polos industriais locais.','Pagamento de salários da equipe de engenharia, custos de hospedagem e largura de banda, investimentos em marketing digital segmentado, aquisição de novos hardwares de processamento e taxas administrativas de manutenção.','Receita recorrente através de assinaturas mensais e anuais, venda de certificados autenticados via blockchain, taxas de licenciamento para escolas parceiras e monetização através de mentorias individuais exclusivas.','Fornecedores de infraestrutura de nuvem, instituições de ensino renomadas, empresas locais da indústria metalmecânica e desenvolvedores independentes de módulos educacionais open-source.',1,'charlene');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(17,'Monitoramento em tempo real de sensores de solo, processamento de dados climáticos via satélite, manutenção de algoritmos de predição de safra e suporte técnico especializado para produtores rurais da Serra Gaúcha.','Maximizar a produtividade agrícola através de dados precisos, reduzindo o desperdício de recursos naturais e defensivos químicos, proporcionando uma gestão sustentável e lucrativa para o pequeno e médio produtor.','Consultoria personalizada pós-venda, treinamentos presenciais nas cooperativas locais, suporte via WhatsApp 24/7 para emergências no campo e comunidade exclusiva para troca de experiências entre usuários.','Pequenos e médios agricultores da região de Garibaldi e Carlos Barbosa, cooperativas vinícolas, empresas de exportação de hortifruti e produtores orgânicos que buscam certificação tecnológica.','Sensores IoT de alta precisão, plataforma de processamento em nuvem escalável, banco de dados histórico de climas regionais e equipe de especialistas em agronomia e tecnologia da informação.','Aplicação móvel offline (para áreas sem sinal), portal de administração web, parcerias com sindicatos rurais locais e demonstrações técnicas em feiras agrícolas da região.','Custos fixos de infraestrutura de nuvem, aquisição e calibração de hardware IoT, logística de instalação no campo, marketing regional e folha de pagamento de especialistas técnicos.','Modelo de assinatura mensal por hectare monitorado, venda de kits de sensores personalizados, serviços de consultoria em análise de solo e licenciamento de dados agregados para seguradoras.','Fabricantes de microcontroladores (ESP32), sindicatos rurais de Carlos Barbosa, cooperativas de crédito agrícola e fornecedores de APIs meteorológicas de alta fidelidade.',1,'b');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(18,'Desenvolvimento de algoritmos de visão computacional para triagem de resíduos, manutenção de infraestrutura de coletores inteligentes e gestão de logística reversa automatizada.','Redução de até 40% nos custos de gestão de resíduos para condomínios e empresas, transformando o lixo descartado em crédito financeiro através de um sistema de gamificação sustentável.','Portal de transparência sobre o impacto ambiental, suporte via aplicativo móvel, consultoria em sustentabilidade para grandes empresas e eventos comunitários de conscientização.','Condomínios residenciais de médio e alto padrão, empresas do setor industrial interessadas em ESG, redes de supermercados e gestores públicos municipais da Serra Gaúcha.','Patentes de tecnologia de sensores de massa, plataforma cloud para processamento de dados em tempo real, frota de veículos elétricos e equipe de engenharia ambiental.','Aplicativo mobile oficial, totens de coleta inteligentes instalados em pontos estratégicos, redes sociais e parcerias com cooperativas de reciclagem da região.','Manutenção preventiva dos coletores, desenvolvimento de software, logística de transporte de resíduos, marketing focado em impacto ambiental e salários da equipe técnica.','Venda de créditos de carbono, taxas mensais de serviço de monitoramento, venda de dados analíticos para indústrias e comercialização de materiais recicláveis processados.','Cooperativas de catadores locais, fabricantes de componentes eletrônicos, empresas de energia renovável e prefeituras de Carlos Barbosa e Garibaldi.',1,'br');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(19,'Otimização de rotas de transporte para indústrias metalmecânicas, monitoramento de carga em tempo real com sensores IoT, manutenção preventiva de frotas e análise preditiva de demanda sazonal.','Redução de 25% no tempo de entrega e 15% nos custos de combustível através de algoritmos de inteligência artificial, garantindo que a produção chegue ao destino com segurança e eficiência máxima.','Plataforma de autoatendimento para rastreio, suporte técnico direto via chat integrado, relatórios semanais de performance logística e consultoria para expansão de rotas de distribuição.','Indústrias de móveis de Bento Gonçalves, fabricantes de ferramentas de Carlos Barbosa, transportadoras de carga pesada e distribuidores de vinho da região de Garibaldi.','Algoritmos proprietários de roteirização, infraestrutura de servidores em nuvem, dispositivos de telemetria avançada e uma equipe multidisciplinar de desenvolvedores e engenheiros de tráfego.','Dashboard web para gestão de frotas, aplicativo para motoristas com GPS integrado, equipe de vendas direta para contas corporativas e presença em congressos de logística nacional.','Hospedagem de servidores escaláveis, desenvolvimento e atualização de software, aquisição de hardware de telemetria, logística de suporte em campo e investimentos em marketing B2B.','Taxa de implementação inicial do sistema, assinatura mensal baseada no número de veículos monitorados, venda de hardware de rastreio e consultoria em otimização de malha logística.','Sindicatos de transportadores locais, fornecedores de hardware eletrônico, empresas de monitoramento via satélite e polos industriais da Serra Gaúcha.',1,'bra');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(20,'Treinamento de redes neurais para reconhecimento de objetos em tempo real, desenvolvimento de interface de voz (VUI) simplificada e integração com dispositivos vestíveis via Bluetooth.','Proporcionar maior autonomia para pessoas com deficiência visual através de um assistente inteligente que descreve o ambiente e lê textos instantaneamente, sem depender de internet.','Comunidade ativa de testadores beta, suporte especializado por canais de acessibilidade, atualizações contínuas baseadas no feedback dos usuários e tutoriais em áudio descritivo.','Pessoas com deficiência visual parcial ou total, instituições de apoio a PCDs, bibliotecas públicas e empresas que buscam adaptar seus espaços para maior inclusão social.','Algoritmos de processamento de imagem proprietários, banco de dados de voz sintética de alta fidelidade, equipe de desenvolvimento e especialistas em acessibilidade digital.','App Store e Google Play, parcerias com ONGs de assistência a cegos, eventos de tecnologia assistiva e venda direta para órgãos governamentais de educação e cultura.','Manutenção de servidores para processamento pesado (opcional), salários da equipe de IA, custos de marketing social e taxas de publicação e licenciamento em lojas de apps.','Modelo de assinatura mensal "Freemium", licenciamento para empresas (B2B), editais de fomento à inovação social e parcerias com fabricantes de óculos inteligentes.','Associações de cegos da Serra Gaúcha, desenvolvedores de hardware open-source, Google (TensorFlow) e Instituições de Ensino Técnico para pesquisa e extensão.',1,'bran');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(21,'Instalação e calibração de sensores ultrassônicos em bacias hidrográficas, análise laboratorial de amostras de água e manutenção preventiva de redes de transmissão de dados via rádio frequência.','Fornecer alertas antecipados de inundações e monitoramento de poluentes químicos em tempo real, garantindo a segurança de comunidades ribeirinhas e a conformidade ambiental de indústrias locais.','Plataforma de dados abertos para órgãos governamentais, suporte consultivo para gestão de crises, newsletters técnicas sobre a saúde dos rios e workshops presenciais com a Defesa Civil.','Prefeituras municipais de Garibaldi e Carlos Barbosa, empresas de saneamento básico, indústrias de curtumes e vinícolas que necessitam de controle rigoroso de efluentes.','Microcontroladores ESP32 adaptados para ambientes úmidos, infraestrutura de recepção de sinal LoRaWAN, algoritmos de análise de séries temporais e equipe de engenharia química e software.','Dashboard de controle para centros de comando, aplicativo de alertas para a população (Push Notifications), relatórios automáticos via e-mail e parcerias com associações agrícolas regionais.','Manutenção da rede física de sensores, custos de processamento de dados em nuvem AWS, logística de deslocamento para áreas rurais, salários da equipe técnica e investimentos em pesquisa de hardware.','Contratos anuais de monitoramento governamental (B2G), venda de relatórios de conformidade para indústrias (B2B), serviços de consultoria em prevenção de desastres e manutenção técnica programada.','Comitês de Bacias Hidrográficas do RS, Defesa Civil Estadual, fornecedores de tecnologia solar (para sensores isolados) e laboratórios de análises químicas credenciados.',1,'brand');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(22,'Desenvolvimento de firmware para medidores inteligentes de corrente, análise de picos de consumo via redes neurais, integração com sistemas supervisórios (SCADA) e consultoria técnica para redução de demanda contratada.','Reduzir em até 20% a fatura de energia elétrica industrial através do monitoramento setorial e identificação de máquinas ineficientes, evitando multas por baixo fator de potência e excedente de demanda.','Plataforma de monitoramento em tempo real com alertas críticos, suporte técnico especializado em engenharia elétrica, relatórios mensais de economia gerada e treinamentos para equipes de manutenção.','Indústrias metalmecânicas de grande porte, fábricas de móveis, cooperativas agroindustriais e shoppings centers localizados na região da Serra Gaúcha que possuem alta demanda energética.','Sensores de corrente não invasivos (SCT), infraestrutura de processamento local (Edge Computing), equipe de engenheiros eletricistas e desenvolvedores full-stack.','Dashboard executivo para gestão financeira, aplicativo mobile para equipes de campo, parcerias diretas com empresas de instalação elétrica e consultores de eficiência energética.','Desenvolvimento de hardware proprietário, licenciamento de softwares de análise de dados, marketing B2B focado em economia real, logística de instalação e suporte pós-venda especializado.','Taxa de instalação do ecossistema de sensores, mensalidade pelo uso da plataforma de análise (SaaS), consultoria para otimização de contratos de energia e venda de relatórios de auditoria.','Distribuidoras de energia locais, fabricantes de componentes elétricos, Institutos de Tecnologia (ISI) e associações industriais de Carlos Barbosa e Garibaldi.',1,'branda');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(23,'Instalação de câmeras inteligentes em cruzamentos críticos, processamento de imagens para contagem de veículos, ajuste dinâmico de tempos semafóricos via IA e integração com sistemas de emergência (SAMU/Bombeiros).','Reduzir o tempo de congestionamento em até 30% e priorizar a passagem de veículos de emergência de forma automatizada, tornando a mobilidade urbana mais fluida e segura para pedestres e motoristas.','Painel de controle centralizado para gestores de trânsito, aplicativo de rotas em tempo real para a população, relatórios de fluxo para planejamento urbano e suporte técnico 24 horas para infraestrutura física.','Secretarias de Planejamento Urbano de Carlos Barbosa, Garibaldi e Bento Gonçalves, empresas de transporte coletivo, frotas de entrega logística e órgãos de segurança pública regional.','Câmeras de alta resolução com processamento de borda (Edge AI), servidores locais de baixa latência, algoritmos de deep learning para detecção de incidentes e equipe técnica de manutenção de campo.','Dashboard de monitoramento municipal, API de integração para aplicativos de GPS (como Waze), editais de inovação tecnológica e apresentações diretas para consórcios de municípios (Cisga).','Aquisição e instalação de hardware óptico, manutenção de servidores e licenças de software, salários da equipe de engenharia e suporte, marketing B2G (Governo) e custos de conectividade fibra/5G.','Contratos de prestação de serviço mensal (SaaS), venda de licenças de software de análise de tráfego, taxas de consultoria para projetos de engenharia viária e manutenção preventiva programada.','Fabricantes de semáforos inteligentes, provedores de internet via fibra óptica, departamentos de trânsito (DMT) e institutos de pesquisa em mobilidade urbana.',1,'brandal');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(24,'Desenvolvimento de modelos de Deep Learning para detecção de uso de capacetes e luvas, integração com câmeras de segurança IP existentes e criação de sistema de alertas sonoros em tempo real.','Redução de zero acidentes graves por falta de EPI através de monitoramento 24/7 automatizado, eliminando a necessidade de supervisão humana constante e garantindo conformidade com a NR-06.','Dashboard de controle para gerentes de RH e Segurança (SESMT), suporte técnico prioritário para paradas de fábrica, relatórios de auditoria automática e consultoria em prevenção de riscos.','Indústrias metalmecânicas e moveleiras da Serra Gaúcha, canteiros de obras de grande porte, cooperativas de processamento de alimentos e centros logísticos de alta rotatividade.','Algoritmos de processamento de imagem proprietários, servidores de processamento local (Edge AI) para evitar latência, equipe de desenvolvedores Python e especialistas em segurança do trabalho.','Venda direta para departamentos de segurança industrial, parcerias com corretoras de seguros empresariais, feiras de segurança do trabalho (FISP) e portal web para gestão de licenças.','Investimento em P&D para melhoria dos modelos de IA, salários da equipe técnica e de suporte, custos de hardware para processamento local e marketing focado no setor industrial.','Licenciamento mensal por câmera monitorada (SaaS), taxa de implementação e treinamento de equipe, venda de hardware otimizado para IA e serviços de consultoria em conformidade normativa.','Fabricantes de EPIs inteligentes, empresas de instalação de CFTV, sindicatos patronais das indústrias locais e órgãos de fiscalização do trabalho para validação de tecnologia.',1,'brandali');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(25,'Desenvolvimento de plataforma de agendamento inteligente, gestão de banco de dados de doadores com tipagem rara, integração de APIs de hospitais regionais e campanhas de marketing geolocalizado.','Reduzir a falta de estoque nos hemocentros da Serra Gaúcha através de um sistema de convocação preditiva, que avisa o doador exatamente quando ele está apto e quando o seu tipo sanguíneo é mais necessário.','Atendimento via chatbot humanizado, programa de pontos e recompensas em parceiros locais, suporte direto aos hospitais e área logada exclusiva para o doador acompanhar seu histórico de exames.','Hospitais públicos e privados de Bento Gonçalves e Carlos Barbosa, hemocentros regionais, doadores frequentes de sangue e empresas que promovem ações de responsabilidade social corporativa.','Servidores de alta disponibilidade para dados sensíveis (LGPD), equipe de desenvolvimento mobile e backend, parcerias com laboratórios de hematologia e algoritmos de análise de estoque crítico.','Aplicativo mobile (Android/iOS), totens informativos em unidades de saúde, redes sociais para campanhas de urgência e parcerias com rádios locais para avisos à comunidade.','Custos de segurança e criptografia de dados médicos, manutenção de infraestrutura cloud, equipe de suporte técnico aos hospitais, investimentos em publicidade e parcerias com marcas para benefícios.','Venda de licenças de gestão para hospitais particulares, taxas de integração com sistemas laboratoriais, parcerias publicitárias éticas e editais de inovação tecnológica em saúde pública.','Secretarias Municipais de Saúde, Hemocentros do Rio Grande do Sul, universidades locais para pesquisa acadêmica e empresas de transporte para facilitar o deslocamento de doadores.',1,'brandaliz');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(26,'Desenvolvimento de algoritmos para precificação de resíduos recicláveis em tempo real, automação do agendamento de coletas industriais e análise de dados para otimização de rotas logísticas.','Transformar resíduos industriais em ativos financeiros através de uma plataforma de marketplace B2B, garantindo 100% de rastreabilidade e conformidade com a Política Nacional de Resíduos Sólidos.','Gestor de conta dedicado para grandes indústrias, portal de autoatendimento para emissão de certificados ambientais, suporte técnico especializado em legislação e canal de feedback contínuo.','Indústrias metalmecânicas da Serra Gaúcha, cooperativas de reciclagem certificadas, empresas de logística e gestores de sustentabilidade de grandes corporações (ESG).','Plataforma cloud escalável, base de dados de compradores de matéria-prima reciclada, patentes de software de rastreio e equipe técnica de desenvolvimento e direito ambiental.','Plataforma web integrada com ERPs industriais, aplicativo para transportadores, participação em fóruns de sustentabilidade e parcerias estratégicas com polos industriais locais.','Manutenção e segurança da infraestrutura de dados, salários da equipe de engenharia e comercial, logística de inspeção técnica, investimentos em marketing B2B e conformidade jurídica.','Comissão sobre cada transação realizada no marketplace, taxas de assinatura mensal por unidade fabril monitorada, consultoria para obtenção de selos verdes e venda de relatórios de impacto.','Sindicatos industriais da região, empresas de auditoria ambiental, prefeituras municipais e fornecedores de tecnologia de pesagem inteligente.',1,'brandalize');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(27,'Sincronização de estoque em tempo real entre lojas físicas e virtuais, desenvolvimento de algoritmos de recomendação personalizada e gestão de logística de entrega no mesmo dia.','Eliminar as barreiras entre o físico e o digital, permitindo que o cliente compre online e troque na loja física com um clique, aumentando a fidelização através de uma jornada sem atritos.','Atendimento via redes sociais com IA humanizada, programa de pontos unificado, consultoria de estilo baseada no histórico de compras e suporte pós-venda automatizado.','Grandes redes de varejo de moda, lojas de departamentos na região sul, e-commerces de médio porte que buscam expandir para o meio físico e consumidores digitais exigentes.','Plataforma de integração (Middleware) proprietária, equipe de especialistas em UX/UI, servidores escaláveis na nuvem e banco de dados unificado de clientes (CDP).','Loja virtual responsiva, aplicativo mobile nativo, pontos de venda (PDV) inteligentes com QR Code e redes sociais integradas para compras diretas.','Desenvolvimento e manutenção da plataforma, custos de hospedagem de dados, marketing de performance, logística de distribuição rápida e salários da equipe de suporte.','Comissão sobre vendas realizadas na plataforma, taxas de licenciamento de software (SaaS), serviços de análise de dados de consumo e venda de assinaturas premium para lojistas.','Operadoras de logística de última milha, gateways de pagamento, influenciadores digitais do setor de varejo e associações comerciais de Carlos Barbosa e região.',1,'v');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(28,'Modelagem de objetos 3D pedagógicos, desenvolvimento de roteiros interativos para ensino técnico e manutenção da plataforma de streaming de conteúdo em Realidade Aumentada.','Transformar o aprendizado teórico em experiências práticas imersivas, permitindo que estudantes visualizem máquinas e processos complexos em 3D através do smartphone.','Suporte pedagógico para professores, comunidade de criadores de conteúdo educativo, webinars mensais sobre metodologias ativas e consultoria para escolas parceiras.','Instituições de ensino técnico (como o SENAI), escolas de ensino médio focadas em tecnologia, centros de treinamento corporativo e estudantes de engenharia e mecânica.','Engine de desenvolvimento Unity, banco de dados de modelos 3D proprietários, equipe de especialistas em UX pedagógico e infraestrutura de servidores de alta performance.','Lojas de aplicativos (Android/iOS), portal web para gestão de turmas, parcerias com editoras de livros didáticos e feiras de inovação educacional em todo o país.','Licenciamento de softwares de modelagem 3D, desenvolvimento de novas funcionalidades no app, hospedagem de arquivos pesados na nuvem e marketing focado no setor educacional.','Assinatura mensal por aluno (modelo B2B e B2C), venda de kits de conteúdo específico para cursos técnicos e licenciamento de tecnologia para editoras de materiais didáticos.','Fabricantes de smartphones, Google (ARCore), conselhos de educação regionais e empresas de hardware para óculos de realidade virtual e aumentada.',1,'vi');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(29,'Integração de protocolos Zigbee e Wi-Fi para controle de iluminação, desenvolvimento de dashboards de consumo de energia e configuração de rotinas de segurança via comandos de voz.','Transformar casas comuns em lares inteligentes e sustentáveis, proporcionando economia de até 30% na conta de luz e maior segurança através de monitoramento remoto simplificado.','Suporte técnico via acesso remoto, fórum de automação para usuários avançados, atualizações de segurança mensais e consultoria para projetos de iluminação inteligente.','Proprietários de imóveis residenciais em reforma, construtoras focadas em prédios inteligentes na Serra Gaúcha, entusiastas de tecnologia e arquitetos de interiores.','Hub de automação proprietário, equipe de desenvolvimento mobile e firmware, banco de dados criptografado e parcerias com fabricantes de dispositivos inteligentes.','Showroom em Carlos Barbosa, loja online oficial, parcerias com escritórios de arquitetura e presença em feiras de construção civil e tecnologia da região.','Importação de componentes eletrônicos, manutenção de infraestrutura de nuvem, salários da equipe técnica de instalação e custos de marketing em plataformas digitais.','Venda de kits de automação (hardware), taxas de instalação personalizada, assinatura de serviços de monitoramento em nuvem e consultoria de eficiência energética.','Lojas de materiais elétricos, provedores de internet locais, fabricantes de sensores IoT e assistentes virtuais (Amazon Alexa / Google Home).',1,'viv');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(30,'Desenvolvimento de contratos inteligentes (Smart Contracts) auditáveis, implementação de nós de rede descentralizados e gestão de chaves criptográficas para autenticação de documentos.','Garantir a imutabilidade e a autenticidade de documentos e diplomas acadêmicos através de registros em blockchain, eliminando fraudes e reduzindo custos de cartório e validação.','Consultoria técnica para integração de sistemas legados, suporte especializado em conformidade com a LGPD, portal de verificação pública e atualizações de protocolo de rede.','Instituições de ensino superior, cartórios digitais, departamentos de RH de grandes empresas e órgãos governamentais que necessitam de alta segurança documental.','Infraestrutura de servidores distribuídos, equipe de desenvolvedores Solidity e Rust, biblioteca de criptografia avançada e consultoria jurídica em direito digital.','Plataforma de certificação online (Web3), API de integração para sistemas de gestão escolar, feiras de segurança cibernética e parcerias com associações de tecnologia.','Taxas de transação na rede (Gas fees), manutenção de servidores de alta disponibilidade, salários de especialistas em segurança e investimentos em auditorias de código.','Taxa por documento autenticado na rede, licenciamento de infraestrutura privada para empresas, serviços de consultoria e assinatura mensal de planos de verificação.','Consórcios de Blockchain nacionais, provedores de certificados digitais (ICP-Brasil), desenvolvedores de hardware de segurança (HSM) e conselhos de classe profissionais.',1,'vivi');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(31,'Curadoria de peças de segunda mão com verificação de qualidade, gestão de logística reversa de embalagens e desenvolvimento de algoritmo de precificação justa por estado de conservação.','Democratizar o acesso à moda de alta qualidade através do consumo consciente, reduzindo o impacto ambiental da indústria têxtil e dando uma segunda vida a roupas e acessórios.','Programa de fidelidade baseado em créditos de carbono, atendimento humanizado via chat, curadoria personalizada por estilo e workshops online sobre moda sustentável e reparos.','Consumidores da Geração Z e Millennials preocupados com o meio ambiente, brechós locais que buscam digitalização e usuários que desejam desapegar de peças de luxo.','Plataforma de e-commerce escalável, centro de distribuição logística, equipe de especialistas em moda e autenticação, e banco de dados de tendências de mercado circular.','Aplicativo mobile dedicado, redes sociais (Instagram/TikTok) integradas, pop-up stores em eventos de moda e parcerias com influenciadores do nicho sustentável.','Manutenção da plataforma tecnológica, custos de higienização e armazenamento, marketing de influência, taxas de processamento de pagamentos e logística de entrega e coleta.','Comissão sobre cada venda efetuada, taxas de serviço de autenticação de luxo, venda de embalagens ecológicas e assinaturas para vendedores profissionais (Power Sellers).','Empresas de logística sustentável (entregas por bike), ONGs de preservação ambiental, lavanderias ecológicas parceiras e influenciadores de consumo consciente.',1,'vivia');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(32,'Implementação de etiquetas inteligentes (QR Codes/RFID) no campo, auditoria de processos de colheita e transporte, e desenvolvimento de interface de consulta para o consumidor final.','Garantir a procedência e a segurança de produtos hortifruti através de um histórico imutável, permitindo que o consumidor saiba exatamente quem produziu seu alimento e quando foi colhido.','Portal de transparência para auditorias, suporte técnico para produtores rurais, canal de feedback para consumidores e relatórios de conformidade para órgãos reguladores de saúde.','Pequenos e médios agricultores orgânicos da Serra Gaúcha, redes de supermercados premium, indústrias de processamento de alimentos e consumidores preocupados com a origem da dieta.','Plataforma de registro distribuído (Blockchain), infraestrutura de hardware para etiquetas RFID, equipe de engenharia de software e especialistas em normas de segurança alimentar.','Etiquetas físicas nos produtos, aplicativo mobile AgroTrust, parcerias com cooperativas agrícolas locais e presença em congressos de inovação no agronegócio e feiras orgânicas.','Produção e logística de etiquetas inteligentes, manutenção dos nós da rede blockchain, custos de certificação técnica, salários da equipe de campo e investimentos em marketing rural.','Taxa por lote de produto rastreado, assinatura mensal de acesso à plataforma para produtores, venda de dispositivos de leitura RFID e consultoria para certificação de origem controlada.','Cooperativas agrícolas de Carlos Barbosa e Garibaldi, laboratórios de análises químicas, fornecedores de tecnologia IoT e associações de produtores orgânicos estaduais.',1,'vivian');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(33,'Mapeamento de pontos turísticos via GPS de alta precisão, curadoria de eventos culturais locais em tempo real e desenvolvimento de algoritmos de recomendação baseados no perfil do viajante.','Oferecer uma experiência de viagem personalizada e sem estresse na Serra Gaúcha, conectando o turista a roteiros exclusivos, gastronomia local e horários de transporte de forma integrada.','Suporte ao turista via concierge digital (IA), comunidade para compartilhamento de fotos e dicas, sistema de avaliações gamificado e parcerias de benefícios em hotéis e restaurantes.','Turistas nacionais e internacionais que visitam a Região da Uva e Vinho, famílias que buscam roteiros autônomos, nômades digitais e agências de turismo receptivo locais.','Base de dados georreferenciada da região, plataforma de processamento de dados em nuvem, equipe de desenvolvimento mobile e parcerias com o setor hoteleiro e gastronômico.','Aplicativo mobile com modo offline, totens interativos em centros de informações turísticas, redes sociais focadas em viagens e parcerias com influenciadores do setor de turismo.','Manutenção dos servidores e APIs de geolocalização, produção de conteúdo multimídia (fotos/vídeos), marketing digital para aquisição de usuários e salários da equipe técnica e comercial.','Comissão sobre reservas feitas pelo app, venda de espaços publicitários para comércios locais, assinaturas para roteiros premium "off-road" e análise de dados agregados para prefeituras.','Secretarias de Turismo municipais, associações de hotéis e pousadas, guias turísticos credenciados e empresas de transporte e locação de veículos da região.',1,'viviane');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(34,'Desenvolvimento de rastreadores solares (trackers) automatizados, monitoramento de eficiência de placas via sensores infravermelhos e análise de dados para predição de geração mensal.','Aumentar a eficiência de sistemas de energia solar em até 25% através de ajustes dinâmicos baseados no clima, garantindo o retorno sobre o investimento (ROI) em tempo recorde.','Dashboard de monitoramento em tempo real, suporte preventivo para limpeza de painéis, relatórios de economia gerada e consultoria para expansão de plantas solares residenciais.','Proprietários de residências com sistemas solares, empresas de instalação fotovoltaica, produtores rurais da região e indústrias que buscam reduzir a pegada de carbono.','Microcontroladores de baixo consumo, algoritmos de rastreamento solar, equipe de engenharia elétrica e infraestrutura de servidores para processamento de telemetria.','Plataforma web para clientes finais, aplicativo mobile de monitoramento, parcerias com instaladores de painéis solares e presença em eventos de sustentabilidade.','Manutenção de hardware de monitoramento, custos de processamento em nuvem, marketing B2B para instaladoras, salários da equipe técnica e logística de atendimento em campo.','Venda de kits de monitoramento inteligente, mensalidade pela plataforma de análise de dados (SaaS), consultoria de eficiência e licenciamento de tecnologia para fabricantes.','Fabricantes de painéis solares, cooperativas de energia renovável, instaladores locais e institutos de pesquisa em energia limpa do Rio Grande do Sul.',1,'bru');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(35,'Desenvolvimento de software de reconhecimento facial offline, integração de sensores biométricos em portarias remotas e manutenção de logs de acesso criptografados em blockchain.','Aumentar a segurança de condomínios reduzindo falhas humanas, oferecendo um controle de acesso rápido e inviolável que pode ser gerenciado totalmente pelo smartphone dos moradores.','Suporte técnico via acesso remoto, interface de gestão simplificada para síndicos, treinamentos presenciais para funcionários e atualizações de segurança automatizadas.','Condomínios residenciais de médio e alto padrão, prédios comerciais, centros logísticos e empresas de segurança privada que buscam modernizar seus serviços de portaria.','Algoritmos de reconhecimento facial de alta precisão, hardware de controle biométrico, infraestrutura de servidores locais e equipe de suporte e desenvolvimento full-stack.','Aplicativo mobile oficial SafeBlock, portal web para administradoras de condomínios, parcerias com instaladores de câmeras e presença em feiras de segurança patrimonial.','Manutenção de servidores e banco de dados, licenciamento de bibliotecas de IA, marketing B2B para administradoras, logística de instalação e salários da equipe de suporte.','Mensalidade por unidade habitacional monitorada, taxa de instalação e configuração do hardware, venda de dispositivos biométricos e consultoria em segurança predial.','Fabricantes de hardware eletrônico, empresas de segurança local, sindicatos de habitação (Secovi) e provedores de internet de fibra óptica de alta disponibilidade.',1,'brun');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(36,'Instalação de sensores de vibração e temperatura em motores industriais, desenvolvimento de modelos de machine learning para detecção de anomalias e integração com sistemas ERP/MES.','Reduzir paradas não planejadas em linhas de produção em até 45%, prevendo falhas em equipamentos críticos antes que ocorram, economizando milhões em manutenção corretiva.','Dashboard de monitoramento de ativos em tempo real, suporte técnico especializado em engenharia de confiabilidade, relatórios mensais de saúde de frota e alertas via Telegram.','Indústrias metalmecânicas de grande porte, fabricantes de componentes automotivos, empresas de papel e celulose e gestores de manutenção de parques fabris automatizados.','Sensores IoT de alta sensibilidade, algoritmos de análise preditiva proprietários, infraestrutura de processamento de dados e equipe multidisciplinar de software e mecânica.','Portal web de gestão industrial, aplicativo mobile para técnicos de manutenção, parcerias com revendas de máquinas industriais e presença em feiras de tecnologia fabril.','Aquisição e calibração de sensores de precisão, desenvolvimento e atualização de algoritmos de IA, custos de servidores em nuvem, logística de instalação e marketing B2B industrial.','Venda de kits de sensores por máquina, assinatura mensal da plataforma de monitoramento (SaaS), serviços de consultoria em confiabilidade e taxas de integração de sistemas.','Fabricantes de rolamentos e motores elétricos, provedores de redes LoRaWAN industriais, associações de classe industriais e consultorias de gestão de ativos.',1,'bruno');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(37,'Desenvolvimento de jogos sérios com captura de movimento via Kinect e sensores inerciais, criação de jornadas de RPG adaptadas para exercícios de fisioterapia e análise biomecânica de dados em tempo real.','Transformar sessões de fisioterapia repetitivas em experiências lúdicas e motivadoras, aumentando a adesão ao tratamento em 60% e permitindo que o paciente realize exercícios corretos de forma autônoma.','Portal de acompanhamento para o fisioterapeuta com gráficos de evolução, suporte técnico remoto para clínicas, comunidade de pacientes gamificada e consultoria para customização de exercícios.','Clínicas de fisioterapia e reabilitação, hospitais ortopédicos, pacientes em recuperação pós-operatória de longa duração, clubes esportivos e idosos que necessitam de manutenção motora.','Engine de desenvolvimento Unreal, sensores de movimento de alta precisão, equipe de game designers e fisioterapeutas, e infraestrutura de processamento de dados biomecânicos na nuvem.','Venda direta para clínicas especializadas, plataforma web para gestão de treinos, parcerias com convênios médicos e presença em congressos de tecnologia em saúde e reabilitação física.','Desenvolvimento e manutenção do software de jogo, aquisição de hardware de captura de movimento, marketing focado no setor de saúde, salários de especialistas e custos de servidores de dados.','Venda de kits de sensores para clínicas, assinatura mensal por paciente ativo (SaaS), licenciamento de jogos específicos para hospitais e consultoria de implantação tecnológica em reabilitação.','Fabricantes de hardware de realidade virtual, conselhos regionais de fisioterapia, operadoras de saúde e universidades para validação clínica e científica dos métodos de gamificação.',1,'g');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(38,'Processamento de imagens multiespectrais capturadas por drones de alta autonomia, treinamento de modelos de redes neurais convolucionais para identificação precoce de pragas e doenças foliares, e integração de dados climáticos históricos com sensores de umidade do solo em tempo real.','Maximizar o rendimento das safras através de diagnósticos ultraprecisos que permitem a aplicação localizada de defensivos, reduzindo o desperdício de insumos químicos em até 40% e garantindo uma produção agrícola muito mais sustentável e economicamente rentável para o produtor.','Consultoria técnica personalizada com agrônomos especializados, plataforma de monitoramento 24/7 com alertas críticos via notificações push e SMS, relatórios detalhados de saúde da cultura por talhão e suporte prioritário durante as janelas críticas de plantio e colheita.','Grandes produtores de grãos e vitivinicultores da região da Serra Gaúcha, cooperativas agrícolas de grande porte que buscam inovação tecnológica, empresas de gestão de ativos agrícolas e investidores do setor de agronegócio focados em métricas ESG e produtividade.','Algoritmos de inteligência artificial proprietários, infraestrutura de processamento de alto desempenho (GPU computing), equipe multidisciplinar composta por cientistas de dados e engenheiros agrônomos, e uma vasta base de dados de imagens rotuladas para treinamento.','Portal web executivo para análise de dados estratégicos, aplicativo móvel de campo para uso offline pelos operadores de máquinas, parcerias diretas com revendas de maquinário agrícola e participação ativa em feiras tecnológicas como a Expodireto e a Expointer.','Elevados investimentos em pesquisa e desenvolvimento de software, manutenção de servidores em nuvem para armazenamento de grandes volumes de dados (Big Data), logística de campo para calibração de sensores físicos e salários de profissionais altamente qualificados.','Cobrança de mensalidade por hectare monitorado (modelo SaaS), taxa de implementação e configuração inicial da rede de sensores, venda de relatórios de auditoria para certificações ambientais e licenciamento de APIs de dados para outras plataformas de gestão agrícola.','Fabricantes de drones agrícolas de precisão, institutos de pesquisa meteorológica, fornecedores de sensores IoT de baixa potência (LoRaWAN) e associações de produtores rurais que buscam o desenvolvimento tecnológico da categoria na região sul.',1,'ga');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(40,'Desenvolvimento de biodigestores automatizados com sensores de pH e temperatura, pesquisa laboratorial para isolamento de colônias bacterianas otimizadas para decomposição acelerada, e criação de sistemas de monitoramento remoto para controle de emissão de gases metano e produção de biofertilizantes líquidos e sólidos.','Oferecer uma solução completa de tratamento de resíduos orgânicos para indústrias alimentícias, eliminando custos de descarte em aterros sanitários e transformando o passivo ambiental em biogás para geração de energia própria e adubo orgânico de alta qualidade para comercialização ou uso em jardins verticais e hortas urbanas.','Consultoria técnica mensal para análise da saúde biológica dos reatores, plataforma de monitoramento em tempo real com dashboards de impacto ambiental (redução de CO2), suporte especializado em engenharia química e programas de treinamento para operadores locais garantindo a máxima eficiência do ecossistema biotecnológico.','Indústrias de processamento de alimentos de grande porte, cooperativas vinícolas da região da Serra Gaúcha, redes de hotéis e resorts que buscam certificações de sustentabilidade (Lixo Zero), e prefeituras municipais interessadas em descentralizar o tratamento de resíduos orgânicos para reduzir gastos com logística e transporte.','Laboratório de microbiologia especializado, equipe de engenheiros de software e biotecnologistas, infraestrutura de servidores para análise de telemetria de sensores, patentes de processos de fermentação acelerada e parcerias com universidades para validação de subprodutos químicos gerados no processo de biodigestão.','Equipe de vendas técnicas B2B focada em grandes contas, portal web de gestão de sustentabilidade para clientes, participação em feiras internacionais de tecnologias ambientais, e webinars educativos sobre economia circular e geração de energia limpa a partir de biomassa residual para o setor industrial e agrícola.','Altos custos de Pesquisa e Desenvolvimento (P&D) para otimização de linhagens bacterianas, aquisição de sensores de precisão industrial, manutenção de infraestrutura de nuvem para Big Data, logística de transporte de bioativadores para clientes distantes e salários de uma equipe técnica altamente especializada e multidisciplinar.','Venda e instalação de unidades de biodigestão customizadas, contratos de manutenção e fornecimento contínuo de ativadores biológicos, taxa de licenciamento do software de monitoramento de eficiência, e prestação de serviços de consultoria para obtenção de créditos de carbono e certificações ambientais internacionais.','Fabricantes de tanques industriais de aço inox, fornecedores de componentes eletrônicos e sensores IoT, institutos de tecnologia e biociências, empresas de transporte de resíduos perigosos e associações de fomento à economia verde e indústrias sustentáveis que apoiam projetos de inovação tecnológica no Brasil.',1,'gaz');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(41,'Desenvolvimento de algoritmos de navegação autônoma com desvio de obstáculos baseado em LiDAR, gestão de tráfego aéreo privado em baixa altitude, manutenção preventiva de frotas de drones multirotores de carga pesada e otimização de rotas ponto-a-ponto para redução de tempo de entrega em áreas de difícil acesso geográfico.','Revolucionar a logística de última milha (last-mile) reduzindo o tempo de entrega de suprimentos médicos e peças industriais críticas em até 80%, operando de forma 100% elétrica e autônoma, eliminando os gargalos do trânsito terrestre e reduzindo drasticamente a emissão de carbono no transporte de mercadorias leves e urgentes.','Interface de rastreamento em tempo real com precisão centimétrica, suporte técnico dedicado para operações de logística crítica, relatórios detalhados de conformidade com as normas da ANAC e DECEA, além de consultoria para integração de estações de pouso e recarga automática (Ninhos de Drones) em centros de distribuição.','Hospitais regionais que necessitam de transporte urgente de exames e bolsas de sangue, indústrias metalmecânicas com unidades fabris distantes, e-commerces de alto valor agregado que buscam entregas "express" no mesmo dia e empresas de logística que operam em zonas rurais ou áreas com infraestrutura rodoviária precária.','Frota de drones com tecnologia de propulsão redundante, software de inteligência artificial para controle de enxame (swarm), infraestrutura de rádio e telemetria de longo alcance, equipe de engenheiros aeroespaciais e desenvolvedores de sistemas embarcados, além de patentes de sistemas de segurança de pouso de emergência.','Plataforma de gestão logística integrada via API para grandes e-commerces, aplicativo mobile para monitoramento de frotas, participação estratégica em fóruns de aviação civil e parcerias diretas com operadoras de infraestrutura logística e armazéns automatizados localizados em pontos estratégicos da Serra Gaúcha.','Elevados investimentos em certificação aeronáutica e conformidade legal, manutenção especializada de baterias de alta densidade energética, custos de pesquisa e desenvolvimento em visão computacional, seguros contra danos a terceiros e salários de pilotos remotos certificados e engenheiros de software e hardware.','Taxa por quilômetro voado ou por entrega realizada, mensalidade por drone alocado em operação exclusiva (modelo DaaS - Drone as a Service), contratos de manutenção de infraestrutura de pouso e licenciamento do software de gestão de tráfego aéreo para outras operadoras logísticas ou órgãos governamentais.','Fabricantes de células de bateria de alto desempenho, agências reguladoras de aviação civil (ANAC), fornecedores de sensores LiDAR e sistemas de GPS RTK, além de empresas de telecomunicações para garantir conectividade 5G constante durante os voos em altitudes operacionais.',1,'gazo');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(42,'Desenvolvimento de sistemas de controle para eletrolisadores de alta eficiência, monitoramento de pureza do hidrogênio em tempo real através de sensores espectroscópicos, automação de sistemas de compressão e armazenamento criogênico, e gestão de protocolos de segurança para transporte de gases inflamáveis em alta pressão com monitoramento via satélite.','Viabilizar a transição energética industrial através do fornecimento de uma plataforma inteligente de gestão de hidrogênio verde, garantindo a rastreabilidade total da origem renovável da energia (Certificação de Origem) e reduzindo o custo operacional de plantas de eletrólise através de algoritmos de otimização de consumo de rede.','Consultoria técnica especializada em infraestrutura de descarbonização, suporte técnico 24 horas para operações críticas de geração de gás, plataforma de visualização de dados de performance energética com relatórios de impacto ambiental para investidores (ESG) e treinamentos constantes em normas de segurança e manuseio de hidrogênio.','Indústrias siderúrgicas e químicas que buscam descarbonização intensiva, empresas de transporte pesado e logística marítima que utilizam células de combustível, governos estaduais focados em políticas de hidrogênio verde e grandes investidores do setor de energia renovável interessados em projetos de infraestrutura de escala internacional.','Patentes de algoritmos de controle de eletrólise, equipe multidisciplinar de engenheiros de software, químicos e físicos, laboratório de testes de células de combustível, infraestrutura de servidores de alta disponibilidade para gestão de ativos remotos e redes de sensores IoT robustas para ambientes industriais e atmosferas explosivas.','Portal corporativo para gestão de frotas e plantas de energia, parcerias estratégicas com fabricantes de eletrolisadores e células de combustível, presença em feiras globais de energia limpa, e consultoria direta para implementação de hubs de hidrogênio verde em zonas portuárias e distritos industriais estrategicamente localizados.','Altos investimentos em pesquisa e desenvolvimento de segurança de hardware, custos de certificação internacional de conformidade ambiental, manutenção de infraestrutura de dados em nuvem, salários de engenheiros de alta especialidade técnica e despesas operacionais para suporte em campo e logística de manutenção de sensores químicos.','Licenciamento de software de gestão de plantas de hidrogênio (SaaS), cobrança de royalties por tecnologia de otimização de eletrólise, consultoria para obtenção de créditos de carbono de alta integridade e taxas de manutenção preventiva e preditiva de sistemas de controle e armazenamento de gases em alta pressão.','Fabricantes de equipamentos de energia solar e eólica, empresas de certificação ambiental internacional, fornecedores de compressores de gás industriais, institutos de tecnologia e pesquisa energética (ISI) e governos nacionais interessados na soberania energética e na exportação de combustíveis de baixo carbono.',1,'gazoli');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(43,'Desenvolvimento de sondas robóticas autônomas com braços articulados para perfuração de regolito, mapeamento espectroscópico de composição mineral de asteroides próximos à Terra (NEAs), simulação de órbitas de transferência de baixa energia e implementação de protocolos de comunicação de longa distância via laser para ambientes de vácuo profundo.','Garantir a soberania de recursos minerais estratégicos para a Terra através da extração automatizada de metais do grupo da platina e água em asteroides, reduzindo o custo de exploração espacial ao permitir o reabastecimento de combustível em órbita (In-Situ Resource Utilization) e fornecendo matéria-prima escassa para a indústria de alta tecnologia.','Plataforma de telemetria em tempo real para investidores e agências espaciais, relatórios trimestrais de prospecção mineral astronômica, suporte técnico especializado em engenharia de sistemas espaciais e parcerias acadêmicas para publicação de dados científicos inéditos sobre a formação do sistema solar e composição de corpos menores.','Agências espaciais governamentais que buscam estabelecer bases lunares ou marcianas, fabricantes de semicondutores e baterias que necessitam de metais raros, empresas de logística orbital e investidores de risco (Venture Capital) focados na nova economia do espaço e na sustentabilidade de recursos a longo prazo para a humanidade.','Frota de naves mineradoras classe "Prospector", algoritmos de inteligência artificial para navegação em ambientes de microgravidade, equipe multidisciplinar composta por astrofísicos, geólogos planetários e engenheiros de software embarcado, além de uma rede de estações terrestres de rastreamento e comunicação espacial profunda.','Portal de dados de prospecção para parceiros estratégicos, participações em fóruns de direito espacial da ONU, parcerias com empresas de lançamento de foguetes (SpaceX/Blue Origin) e conferências internacionais de mineração e exploração de recursos extraplanetários para captação de novos contratos e investimentos de longo prazo.','Elevadíssimos custos de Pesquisa, Desenvolvimento e Inovação (PD&I) em hardware resistente à radiação cósmica, seguros aeroespaciais de alto risco, manutenção de infraestrutura de controle de missão terrestre, salários de profissionais de altíssima especialização e custos logísticos de lançamento e inserção em órbitas interplanetárias.','Venda antecipada de contratos de fornecimento de minerais raros, taxas de consultoria para missões de exploração governamentais, licenciamento de tecnologias de pouso e ancoragem em microgravidade e serviços de reabastecimento de água e oxigênio para estações espaciais e futuras colônias lunares ou marcianas.','Fabricantes de propulsão iônica, agências reguladoras de exploração espacial internacional, mineradoras terrestres interessadas em diversificação tecnológica, fornecedores de painéis solares espaciais de alta eficiência e institutos de astrofísica e geociências planetárias de renome global.',1,'m');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(44,'Desenvolvimento de algoritmos de renderização, curadoria de catálogo de móveis digitais e processamento de fotos de ambientes reais.','Permitir que usuários visualizem móveis e cores em suas casas usando apenas a câmera do celular com realismo impressionante.','Chatbot de auxílio criativo, comunidade para compartilhamento de projetos e suporte técnico via e-mail e redes sociais.','Pessoas em processo de reforma ou mudança, arquitetos autônomos e lojas de móveis que buscam novas formas de venda.','Plataforma mobile, banco de dados de modelos 3D, equipe de desenvolvedores e servidores de processamento de imagem.','App Store, Google Play, parcerias com influenciadores de decoração e anúncios em redes sociais visuais (Instagram/Pinterest).','Manutenção do aplicativo, hospedagem em nuvem, marketing digital e salários da equipe de desenvolvimento e design.','Assinatura mensal para profissionais, comissão sobre móveis vendidos pelo app e venda de pacotes de filtros premium.','Fabricantes de móveis, lojas de tintas, desenvolvedores de motores gráficos e estúdios de design de interiores.',1,'dipp');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(45,'Desenvolvimento de polímeros biodegradáveis com sensores de frescor integrados, testes de resistência mecânica e monitoramento químico de gases de decomposição.','Reduzir o desperdício de alimentos através de embalagens que mudam de cor ao detectar a perda de frescor, garantindo segurança alimentar e sustentabilidade ambiental.','Plataforma de rastreio de lote para indústrias, suporte técnico para integração em linhas de envase e portal de transparência sobre compostagem dos materiais.','Indústrias de laticínios e frigoríficos, redes de supermercados focadas em produtos orgânicos e exportadores de frutas de alto valor agregado da região.','Laboratório de biomateriais, equipe de desenvolvedores de firmware, banco de dados de indicadores químicos e parcerias com institutos de polímeros.','Venda direta B2B, feiras de embalagens (Brasil Pack), parcerias com empresas de logística de frios e plataforma web de pedidos e consultoria técnica.','Pesquisa e desenvolvimento de materiais, manutenção de servidores de dados, marketing para o setor industrial e custos de certificação de grau alimentício.','Venda por milhar de embalagens produzidas, licenciamento da tecnologia de sensores e consultoria para redução de perdas logísticas em cadeias de suprimentos.','Fabricantes de plásticos biodegradáveis, fornecedores de pigmentos reagentes, agências de vigilância sanitária e associações de produtores de alimentos.',1,'bo');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(46,'Desenvolvimento de algoritmos de visão computacional para detecção de humanos, programação de trajetórias seguras para braços robóticos e integração com sistemas de picking.','Aumentar a produtividade em centros de distribuição através de robôs que trabalham lado a lado com humanos, eliminando tarefas repetitivas e reduzindo erros de separação.','Treinamento operacional para equipes de chão de fábrica, interface de controle intuitiva via tablet e suporte técnico especializado em manutenção preventiva e corretiva.','Centros de distribuição de e-commerce, indústrias metalmecânicas com alta rotatividade de peças e operadoras logísticas que buscam modernização tecnológica.','Braços robóticos colaborativos, sensores de segurança de última geração, equipe de engenheiros de software e licenças de sistemas operacionais de robótica (ROS).','Venda consultiva direta, demonstrações em feiras de tecnologia industrial, portal web de soluções e parcerias com integradores de sistemas de automação.','Aquisição de hardware robótico, salários de especialistas em IA e robótica, marketing focado no setor industrial e custos de certificação de segurança NR-12.','Venda de células robóticas completas, contratos de manutenção mensal, licenciamento de software de inteligência logística e consultoria em automação de processos.','Fabricantes de robôs (UR/Kuka), fornecedores de sensores ópticos, Institutos SENAI de Tecnologia e associações de logística e transporte regional.',1,'bor');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(47,'Monitorização de tráfego de rede industrial (OT), deteção de intrusões em tempo real, auditorias de vulnerabilidades em PLCs e implementação de firewalls de próxima geração.','Proteger linhas de produção contra ataques cibernéticos e sequestro de dados (Ransomware), garantindo a continuidade operacional e a integridade dos processos fabris.','Suporte técnico em regime 24/7 para incidentes críticos, relatórios mensais de conformidade de segurança e consultoria para implementação da norma ISO 27001.','Indústrias automatizadas de grande porte, centrais de distribuição de energia, empresas de saneamento e gestores de infraestruturas críticas nacionais.','Softwares de análise de pacotes profundos (DPI), especialistas em segurança ofensiva e defensiva, e servidores de monitorização descentralizados.','Plataforma de gestão de segurança na nuvem, parcerias com fornecedores de hardware industrial, feiras de cibersegurança e equipas de vendas consultivas especializadas.','Licenciamento de ferramentas de proteção, manutenção de laboratórios de testes de intrusão, salários de peritos em segurança e infraestrutura de rede segura.','Subscrição anual de monitorização (MSSP), venda de licenças de software proprietário, taxas de consultoria em auditoria e serviços de resposta a incidentes.','Fabricantes de equipamentos de rede (Cisco/Fortinet), agências nacionais de segurança cibernética, institutos de tecnologia e fornecedores de software industrial.',1,'borg');
INSERT INTO "tb_canva" ("id_canva","atividades_chaves","proposta_chave","relacionamentos_clientes","segmentos_clientes","recursos_chaves","canais","estrutura_custos","fluxo_receita","parceiros_chaves","processado","usuario") VALUES(48,'Desenvolvimento de redes neurais para análise de padrões de consumo, monitoramento de transações bancárias em tempo real e criação de sistemas de alerta antecipado para atividades suspeitas.','Proteger instituições financeiras e seus clientes contra fraudes digitais complexas, reduzindo perdas financeiras através de uma IA que aprende e evolui com cada tentativa de golpe.','Consultoria especializada em segurança bancária, suporte técnico prioritário para bancos parceiros, interface de gestão de alertas e relatórios detalhados de prevenção de riscos.','Bancos digitais e tradicionais, operadoras de cartões de crédito, fintechs de meios de pagamento e grandes e-commerces que gerenciam transações financeiras internas.','Algoritmos proprietários de Machine Learning, base de dados histórica de padrões de fraude, equipe de especialistas em segurança da informação e infraestrutura de processamento rápido.','Venda consultiva direta (B2B), integração via API segura, presença em conferências de tecnologia financeira e parcerias com associações bancárias nacionais e internacionais.','Investimento contínuo em pesquisa de novas ameaças cibernéticas, manutenção de servidores de alta performance, salários de cientistas de dados e custos de certificações de segurança.','Taxa por volume de transações monitoradas, mensalidade fixa pelo licenciamento da plataforma (SaaS), consultoria para auditoria de segurança e venda de relatórios de tendências de fraude.','Bandeiras de cartão de crédito, provedores de infraestrutura de nuvem segura, institutos de tecnologia e especialistas em direito digital e conformidade bancária.',1,'Borge');
CREATE TABLE tb_conhecimentos (
  id_conhecimentos INTEGER PRIMARY KEY,
  plano_curso TEXT DEFAULT NULL,
  conhecimentos_aplicados TEXT NOT NULL,
  capacidades_aplicadas TEXT NOT NULL,
  usuario TEXT DEFAULT NULL,
  FOREIGN KEY (usuario) REFERENCES tb_equipe (nome_equipe) ON DELETE CASCADE ON UPDATE CASCADE
);
CREATE TABLE tb_cronograma (
  id_cronograma INTEGER PRIMARY KEY,
  processo TEXT NOT NULL,
  etapas TEXT NOT NULL,
  responsavel TEXT NOT NULL,
  data_inicio DATE DEFAULT NULL,
  data_final DATE DEFAULT NULL,
  observacoes TEXT NOT NULL,
  usuario TEXT DEFAULT NULL,
  FOREIGN KEY (usuario) REFERENCES tb_cadastros (nome_usuarios) ON DELETE CASCADE ON UPDATE CASCADE,
  FOREIGN KEY (usuario) REFERENCES tb_equipe (nome_equipe) ON DELETE CASCADE ON UPDATE CASCADE,
  FOREIGN KEY (id_cronograma) REFERENCES tb_equipe (id_equipe) ON DELETE CASCADE ON UPDATE CASCADE
);
CREATE TABLE tb_curriculo_alunos (
  id_aluno INTEGER PRIMARY KEY,
  nome TEXT NOT NULL,
  data_nacimento DATE DEFAULT NULL,
  cpf TEXT NOT NULL,
  empresa_vinculado TEXT DEFAULT NULL,
  projeto TEXT NOT NULL,
  telefone TEXT NOT NULL,
  email TEXT NOT NULL,
  nome_reponsavel TEXT DEFAULT NULL,
  numero_responsavel TEXT DEFAULT NULL,
  email_repsonsavel TEXT DEFAULT NULL,
  habilidades TEXT DEFAULT NULL,
  fez_projeto TEXT DEFAULT NULL,
  cidade TEXT DEFAULT NULL,
  motivo_projeto TEXT NOT NULL,
  aprendo_mais TEXT DEFAULT NULL,
  prefiro_trabalhar TEXT DEFAULT NULL,
  usuario TEXT DEFAULT NULL,
  FOREIGN KEY (usuario) REFERENCES tb_equipe (nome_equipe) ON DELETE CASCADE ON UPDATE CASCADE
);
