CREATE TRIGGER trg_atualiza_nome_empresa AFTER UPDATE ON tb_empresas
FOR EACH ROW
WHEN OLD.nome_empresa <> NEW.nome_empresa
BEGIN
    UPDATE tb_informacoes_complementares
    SET empresa = NEW.nome_empresa
    WHERE empresa = OLD.nome_empresa;

    UPDATE tb_curriculo_alunos
    SET empresa_vinculado = NEW.nome_empresa
    WHERE empresa_vinculado = OLD.nome_empresa;
END;
